"""
MKT Context Commentary — Deuteronomy 28–29 (97 verses)
Run: python3 scripts/zc-context-deuteronomy-28-29.py

Key decisions:
- Ch 28: Frame blessings/curses against ANE suzerainty treaty curse-lists
  (Esarhaddon's vassal treaties, Hittite treaties). Note the 14:54 blessing-to-curse
  ratio as covenant realism. Eagle-nation (vv49-57) and diaspora (vv64-68) are the
  historical horizon. Cannibalism-siege (vv53-57) historically fulfilled in 597/586 BCE.
- Ch 29: Moab covenant as second, additional covenant (not replacement of Sinai).
  Paul quotes v4 in Rom 11:8; Heb 12:15 uses v18's root-of-bitterness. Extension-across-
  time (vv14-15) is the covenant's intergenerational principle. V29 is the OT's
  key epistemological limit-verse, paralleled in Rom 11:33-36.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


DEUT = {
    "28": {
        "1": "<p>\"If you fully obey the LORD your God and carefully follow all his commands I give you today, the LORD your God will set you high above all the nations on earth\" — the opening condition frames the entire blessing-and-curse structure of chapter 28 as the consequence-catalogue of a suzerainty treaty. The great empires of the ANE formalized their treaties with vassal states using a fixed structure: preamble, historical prologue, stipulations, deposit and reading instructions, witness list, and then blessing/curse lists. Hittite suzerainty treaties (14th-13th c. BCE) contain elaborate curse-catalogues; Esarhaddon's vassal treaties (672 BCE) contain multi-page curse-lists invoking dozens of ANE deities. Deuteronomy 28 is the most sustained parallel to this treaty-curse genre in the ancient world, but with YHWH as the sole divine witness and enforcer. The opening conditional makes clear that the blessings are not automatic gifts but covenant-consequences.</p>",
        "2": "<p>\"All these blessings will come upon you and overtake you if you obey the LORD your God\" — the verb \"overtake\" (<em>hasigucha</em>) is the same word used for the curses in v15: \"all these curses will come upon you and overtake you.\" The symmetry is precise — blessings pursue the obedient as curses pursue the disobedient. The blessings are not passive receipts but active forces that pursue and catch the covenant-keeper. The relentless-grace image is the counterpart to the relentless-judgment of the curse section.</p>",
        "3": "<p>\"You will be blessed in the city and blessed in the country\" — the first of the seven blessing-couplets that mirror exactly the seven curse-couplets of vv16-19. The city/country pairing is a merism encompassing all human habitations — sedentary urban life and pastoral/agricultural rural life. The complete geographical coverage signals that the blessing is total and pervasive: no sphere of life is excluded from YHWH's abundance when the covenant is kept.</p>",
        "4": "<p>\"The fruit of your womb will be blessed, and the crops of your land, and the young of your livestock\" — the three primary realms of ancient agricultural life: human fertility, crop fertility, and livestock fertility. All three represent the continuation and abundance of life. In the ANE, these three domains were precisely what the fertility deities (Baal, Asherah, Dagan) were credited with providing. Deuteronomy's blessings make a direct counter-claim: YHWH, not the Canaanite fertility pantheon, controls the womb, the ground, and the herd.</p>",
        "5": "<p>\"Your basket and your kneading bowl will be blessed\" — the basket (<em>tene</em>, H2935) and kneading bowl (<em>mishereth</em>, H4863) are the two instruments of food processing: the basket that collects and carries grain and fruit, and the bowl where dough is mixed for bread. The blessing of these implements stands for the blessing of all food preparation — from harvest to table. The inclusion of domestic implements alongside crops signals that the blessing reaches into the domestic sphere of daily labor, not just the field.</p>",
        "6": "<p>\"You will be blessed when you come in and blessed when you go out\" — the come-in/go-out merism covers all of life's movement: entry and departure, home and road, rest and work. This is the complete temporal and spatial coverage of blessing. The same phrase is used in Psalm 121:8 (\"The LORD will watch over your coming and going both now and forevermore\") as a comprehensive statement of divine protection. The blessing is not situational but accompanies the covenant-keeper through all transitions.</p>",
        "7": "<p>\"The LORD will cause the enemies who rise up against you to be defeated before you. They will come at you from one direction but flee in seven\" — the seven-direction flight: the attacking enemy, however organized, scatters in seven directions (a numerical symbol of completeness and disarray). The military reversal is YHWH-caused (<em>yiten YHWH</em>) — Israel does not achieve its military victories through superior tactics or armament but through covenant-relationship. The one-against-many attack becoming seven-way retreat is the structural inversion of the siege-and-defeat threat of the curses (vv25,49-52).</p>",
        "8": "<p>\"The LORD will send a blessing on your barns and on everything you put your hand to\" — the storehouse (<em>meguroteicha</em>, H618 — grain storage pits or storehouses) receives the divine blessing. Storage facilities represent the security of future provision: full barns mean safety from famine. The phrase \"everything you put your hand to\" (<em>bemishlach yadecha</em>) appears throughout Deuteronomy (12:7,18; 15:10; 23:20; 28:8,20) as a formula for work's productivity. The blessing is economically comprehensive — from the current harvest to the stored reserve to future labor.</p>",
        "9": "<p>\"The LORD will establish you as his holy people, as he swore to you, if you keep his commands and walk in his ways\" — the establishment as holy people (<em>yequimcha YHWH lo le-am qadosh</em>) is the covenant-identity goal: Israel's status as YHWH's holy nation (Exod 19:6) is actualized through covenant obedience, not merely declared. The oath-appeal grounds the promise in YHWH's prior commitment to the patriarchs — the blessings are not arbitrary incentives but the fulfillment of ancient promises. The conditional \"if\" (<em>im</em>) maintains the covenant's bilateral structure.</p>",
        "10": "<p>\"All the peoples of the earth will see that you bear the name of the LORD, and they will be in awe of you\" — the nations' reaction to Israel's covenant prosperity: the phrase \"bear the name of the LORD\" (<em>shem YHWH niqra aleicha</em>) describes ownership and protection. To bear someone's name in the ANE was to belong to them and be under their authority and protection. Israel bearing YHWH's name means the nations recognize Israel as YHWH's possession — and respond with awe (<em>uyarau mimeka</em>). The international witness-function of covenant blessing is one of Deuteronomy's consistent theological points (cf. 4:6-8: the nations observe Israel's wisdom and nearness to God).</p>",
        "11": "<p>\"The LORD will grant you abundant prosperity\" — the covenant prosperity (<em>hotirekha YHWH letovah</em>) is not merely individual wealth but communal flourishing. The three domains of v4 (womb, land, livestock) are restated here as the content of abundance. The verb <em>hotir</em> (make abundant, make surplus) points to more than subsistence — the covenant-community living in full prosperity has resources that overflow its own needs, enabling the generosity that the social laws require.</p>",
        "12": "<p>\"The LORD will open his abundant storehouse — the sky — to send rain on your land in season and to bless all your work. You will lend to many nations but not borrow from any\" — the sky as YHWH's storehouse (<em>otzer tov</em>): YHWH controls the rain-store that the Baal cult claimed to control. The seasonal rain (<em>geshem artzecha be-itto</em>) is YHWH's gift, not Baal's. The economic consequence of agricultural abundance: Israel becomes a lending nation, not a borrowing one — the reversal of the creditor-debtor relationship that marks political dominance (Prov 22:7). The Assyrian and Babylonian demand for tribute from vassal Judah was the historical fulfillment of the curse-version of this promise (v44).</p>",
        "13": "<p>\"The LORD will make you the head, not the tail; you will always rise, never fall\" — the head/tail political metaphor: the head leads and directs; the tail follows and is subordinate. In the ANE political world, great powers were heads (they imposed tribute, set terms, commanded armies) and vassal states were tails (they paid tribute, received terms, supplied troops). The blessing transforms Israel's political position from peripheral to central, from dependent to independent. The \"always rise, never fall\" formula is a comprehensive promise of political stability and dignity — the exact inversion of what the curse describes (v43-44).</p>",
        "14": "<p>\"And if you do not turn aside from any of the commands I give you today, to the right or to the left, by going after other gods and serving them\" — the concluding condition for the blessing section: the right/left non-deviation formula (cf. 5:32; 17:11,20) defines faithful covenant-keeping as non-deviation from YHWH's commands. The specific threat named is idolatry: \"going after other gods\" (<em>lelekhet acharei elohim acherim</em>) is the breach that triggers the curses. The blessing section's conclusion pointing to its own negation sets up the transition to the curse section.</p>",
        "15": "<p>\"But if you do not obey the LORD your God and do not carefully follow all his commands and statutes I give you today, all these curses will come upon you and overtake you\" — the curse section (vv15-68) begins with the exact structural mirror of the blessing's opening (v1). The curses overtake (<em>hasigucha</em>) the disobedient as the blessings pursue the obedient (v2). The 54 curse-verses versus 14 blessing-verses (almost 4:1 ratio) reflects covenant-legal realism: the specific consequences of disobedience require more elaboration than the general consequence of obedience, because the various forms of failure need specific documentation. ANE treaty curse-lists similarly dwarf their blessing counterparts.</p>",
        "16": "<p>\"You will be cursed in the city and cursed in the country\" — the inverted mirror of v3: the city/country merism now receives cursing instead of blessing. Verses 16-19 are exact negations of vv3-6: every sphere blessed in obedience becomes cursed in disobedience. The literary symmetry enforces the theological point: what YHWH can bless, YHWH can curse. The domains of life are not neutral or self-determining — they are responsive to the covenant relationship.</p>",
        "17": "<p>\"Your basket and your kneading bowl will be cursed\" — the inversion of v5: the food-processing implements that blessed the harvest in obedience now curse the food chain in disobedience. What is gathered is insufficient; what is prepared is inadequate. The curse reaches into domestic food-processing, not just agricultural production.</p>",
        "18": "<p>\"The fruit of your womb will be cursed, along with the crops of your land, the calves of your herds, and the lambs of your flocks\" — the inversion of v4: the three fertility domains (human, agricultural, livestock) that were blessed in obedience now fall under curse. In ANE fertility theology, the curse of womb and ground was the ultimate terror. The Baals and Asherahs were worshiped precisely to prevent these curses; Deuteronomy's irony is that worshiping them instead of YHWH (v14's breach) triggers the curse of the very domains they claimed to protect.</p>",
        "19": "<p>\"You will be cursed when you come in and cursed when you go out\" — the inversion of v6: the complete coverage of all movement and activity that was blessed in obedience now receives curse in disobedience. No moment of transition, no spatial movement, carries anything but the covenant's judgment. The comprehensive cursing of movement mirrors the comprehensive blessing of v6 but inverts its outcome completely.</p>",
        "20": "<p>\"The LORD will send on you disaster, confusion, and failure in everything you undertake, until you are quickly destroyed because of the evil you have done in forsaking him\" — three curse-agents: <em>me'era</em> (disaster/curse, the divine sanction), <em>mehumah</em> (confusion, panic), and <em>miger'et</em> (failure, rebuke). The three operate together to undermine every human project: disaster hits externally, confusion disrupts internally, and failure eliminates productivity. The ground for judgment: \"the evil you have done in forsaking him\" (<em>maasecha asher azavtani</em>).</p>",
        "21": "<p>\"The LORD will plague you with disease until he has wiped you out from the land you are entering to possess\" — the land-possession language of the conquest is reversed: Israel enters the land to possess it, but the land becomes the site of destruction. The plague (<em>dever</em>, H1698 — epidemic disease, often the fifth of the Exodus plagues) will not stop until the land is cleared of the disobedient Israel. This is the historical pattern fulfilled in 722 BCE (Assyrian deportation of the northern kingdom) and 586 BCE (Babylonian exile).</p>",
        "22": "<p>\"The LORD will strike you with tuberculosis, fever, inflammation, scorching heat, and drought — with blight and mildew\" — seven specific disease and agricultural curses: <em>shachefet</em> (wasting disease/tuberculosis), <em>qaddachat</em> (fever), <em>dalleqet</em> (inflammation), <em>chamum</em> (scorching heat), <em>cherev</em> (sword or drought), <em>shiddafon</em> (blight), <em>yeraqon</em> (mildew/yellowing of grain). The seven-fold listing mirrors the seven blessings; the agricultural diseases (blight, mildew) attack the crops directly while the bodily diseases attack the people. When the covenant breaks, both people and land suffer simultaneously.</p>",
        "23": "<p>\"The sky above you will be like bronze, the ground beneath you like iron\" — the climate-reversal curse: the sky that was YHWH's abundant storehouse of rain (v12) becomes impenetrable bronze — no moisture descends. The ground that was YHWH's gift to Israel becomes unyielding iron — no root penetrates, no seed sprouts. Rain was already scarce in Canaan compared to Egypt's Nile irrigation; a drought curse in this landscape was catastrophic. The ANE rain-god was supposed to prevent exactly this; YHWH sends it as covenant judgment.</p>",
        "24": "<p>\"The LORD will turn the rain of your land into dust and powder; it will come down from the sky until you are destroyed\" — the inversion of productive rain: instead of life-giving water from heaven, dust and fine powder rain down. The image may refer to the <em>sirocco</em> (khamsin), the hot, desiccating east wind that blows across Canaan from the desert — it brings dust and withers vegetation. YHWH sends this in place of the spring rains, reversing the weather patterns on which Canaanite agriculture depended.</p>",
        "25": "<p>\"The LORD will cause you to be routed before your enemies. You will march out against them from one direction but flee in seven\" — the precise inversion of v7: the blessing gave Israel military victory by scattering enemies in seven directions; the curse gives enemies military victory by scattering Israel in seven directions. The same \"one direction in, seven directions out\" formula is applied with the roles reversed. The same YHWH who grants military victory to the covenant-keeper directs military defeat against the covenant-breaker.</p>",
        "26": "<p>\"Your dead bodies will become food for all the birds and the wild animals, and there will be no one to frighten them away\" — the unburied dead was among the most shameful possible fates in the ANE. Proper burial was essential for honor and for the peace of the dead's spirit in many ancient cultures. The curse of unburied bodies eaten by scavengers inverted the ANE honor-death ritual entirely. Jeremiah repeatedly describes this curse as fulfilled in the Babylonian destruction (Jer 7:33; 8:1-2; 16:4; 34:20). The detail \"no one to frighten them away\" indicates complete social collapse: no surviving community member can perform even this minimal protective duty.</p>",
        "27": "<p>\"The LORD will afflict you with the boils of Egypt and with tumors, festering sores, and an itch that cannot be healed\" — the Egypt-plague diseases in reverse: Israel sent to Canaan to escape Egypt's diseases now finds those same diseases following them in Canaan. The \"boils of Egypt\" (<em>shechin mitzrayim</em>) — the sixth Exodus plague (Exod 9:10-11) — become a covenant curse in Israel's own land. The incurability prevents even medical management of the suffering. The return of Egypt's plagues against Israel in their own land is one of the curse section's recurring ironies.</p>",
        "28": "<p>\"The LORD will afflict you with madness, blindness, and confusion of mind\" — three psychological/neurological curses: <em>shigga'on</em> (madness), <em>ivvaron</em> (blindness), and <em>timhon levav</em> (confusion of mind/bewilderment of heart). The external agricultural and military curses now reach into the inner person — the faculties of perception, reason, and orientation are disabled. The practical consequences follow in v29: they grope in darkness at midday and cannot accomplish any goal.</p>",
        "29": "<p>\"At midday you will grope about like a blind person in the dark\" — the blindness-curse renders daylight useless: the covenant-breaker cannot see even in full sun, groping like a blind person in darkness. The reversal: the sun that was YHWH's creation-gift provides no guidance to those under the curse. The parallel to Egypt's plague of darkness (Exod 10:21-23) is deliberate: the Egyptians groped in darkness while Israelites had light; now Israelites grope while others see clearly.</p>",
        "30": "<p>\"You will be pledged to a woman, but another man will sleep with her. You will build a house, but you will not live in it. You will plant a vineyard, but you will not even begin to enjoy its fruit\" — the three frustration-curses parallel the exemptions from military service in Deut 20:5-7 (the man who built a house but hasn't dedicated it; planted a vineyard but not enjoyed it; betrothed a woman but not married her). The labor investment is made but the enjoyment is seized by another. In the curse-context, the war itself delivers these deprivations universally.</p>",
        "31": "<p>\"Your ox will be slaughtered in your sight, but you will eat none of it. Your donkey will be stolen right in front of you and will not be returned. Your sheep will be given to your enemies, and no one will rescue them\" — the helpless-observation curse: the covenant-breaker watches his animals slaughtered, stolen, and given away and cannot prevent any of it. The ox (draft animal for plowing), donkey (transport), and sheep (wool and meat) are the three foundational livestock of the Israelite economy. Their loss means agricultural collapse, transportation failure, and food/clothing deprivation.</p>",
        "32": "<p>\"Your sons and daughters will be given to another nation while you watch — your eyes straining with longing for them all day long, but powerless to do anything\" — the deportation of children as the deepest personal curse: the loss of children through deportation is worse than their death because the parents survive in helpless longing. The historical fulfillment: the Babylonian deportation of Judah scattered families across the empire, separating children from parents permanently in many cases (Lam 1:5; 5:2-3).</p>",
        "33": "<p>\"A nation you do not know will devour the produce of your soil and all your labor. You will be oppressed and crushed relentlessly\" — the foreign-nation harvest curse: the land's produce, cultivated by Israel's labor, is consumed by a foreign nation that Israel doesn't even know. The emphasis on \"you do not know\" (<em>asher lo yadatta</em>) heightens the alienation. The oppression and crushing are relentless — describing precisely the Assyrian and Babylonian tributary system imposed on Israel and Judah.</p>",
        "34": "<p>\"Until you are driven mad by what you see\" — the accumulated vision of the curses produces madness: the covenant-breaker must watch the serial theft, deportation, and subjugation described in vv30-33, and the helpless watching eventually destroys mental stability. The verse functions as a summary-bridge between the initial curse-series (vv15-33) and the extended curse-series beginning in v36.</p>",
        "35": "<p>\"The LORD will afflict your knees and legs with painful, incurable boils — from the sole of your foot to the top of your head\" — the head-to-toe body-curse: the boils that covered the Egyptians in Exod 9:10 now cover Israel from feet to head. The specific focus on knees and legs indicates the inability to stand, walk, or flee — the physical embodiment of the paralysis described in vv29-34. The incurability matches v27's formulation: medical intervention cannot break the covenant curse because it is a divine judgment.</p>",
        "36": "<p>\"The LORD will drive you and the king you set over you to a nation unknown to you or your ancestors, where you will serve gods of wood and stone\" — the exile of both people and king: the king, promised in 17:14-20 as a conditional institution, will share the people's exile fate. The exile-destination is unknown — not Egypt (whose subjugation Israel already knew) but a new, alien empire. The worst element of exile: living in contexts of forced idol-worship. The irony: they abandoned YHWH to serve idols at home; in exile, they are surrounded by idol-worship they did not choose.</p>",
        "37": "<p>\"You will become a thing of horror and an object of ridicule and mockery among all the nations where the LORD drives you\" — the honor-shame dimensions of exile: in the ANE's honor-culture, national defeat was a statement about the defeated nation's god. The \"object of ridicule and mockery\" (<em>mashal ulsheninah</em>) was the proverbial comparison by which other nations discussed disaster: \"become like Israel\" as a byword for catastrophic defeat. The Psalms of Lament preserve this experience (Ps 44:13-16; 79:4; Lam 2:15-16).</p>",
        "38": "<p>\"You will plant much seed but harvest little, because locusts will eat it\" — the first of the agricultural-frustration curses (vv38-42): work without reward. The locust-plague was the most devastating agricultural disaster in the ancient Near East — the eighth Exodus plague (<em>arbeh</em>) could strip a field completely in hours. Joel 1-2 depicts an actual locust plague as both historical disaster and eschatological judgment. The covenant-breaker plants and sows in hope but harvests nothing.</p>",
        "39": "<p>\"You will plant and tend vineyards but drink no wine and gather no grapes, because worms will eat them\" — the vine-curse: worms (<em>tola'at</em>, H8438) destroy the vineyards before harvest. The vine was Israel's most prominent agricultural symbol (Deut 8:8; Isa 5:1-7; John 15:1) — the blessing and fruitfulness of the land made visible. Its destruction by worms is a slow internal destruction that renders the vine useless while still appearing alive. The vine-without-fruit becomes a prominent prophetic image (Isa 5:2,4; Jer 2:21; Ezek 15:1-8).</p>",
        "40": "<p>\"You will have olive trees throughout your land but will not use the oil, because the olives will drop off\" — olive oil was fundamental to the ancient Israelite economy: food, fuel for lamps, skin ointment, and ritual anointing. An olive tree required years of cultivation before bearing fruit. The curse is that the trees remain but the olives fall prematurely, making the oil unavailable. The effort investment in maintaining olive orchards is entirely lost.</p>",
        "41": "<p>\"You will have sons and daughters but you will not keep them, because they will go into captivity\" — the child-deportation curse restated from v32: even the children born during the covenant-breaking period will not remain in Israel's household but will be taken captive. The covenant-breaker cannot build a new generation to replace what has been lost. The future is cut off along with the present.</p>",
        "42": "<p>\"Swarms of locusts will take over all your trees and the crops of your land\" — the locust-conclusion to the agricultural curse series: after the specific losses (grain, vine, olive, children), the comprehensive locust invasion devours everything else. The phrase \"take over\" (<em>yirash</em>) uses the dispossession language of conquest — the locust-swarm inherits the land that Israel inherited from the Canaanites. The word <em>yirash</em> (possess, dispossess, H3423) is the same word used throughout Deuteronomy for Israel's conquest of Canaan.</p>",
        "43": "<p>\"The foreigner living among you will rise higher and higher while you sink lower and lower\" — the social-inversion curse: the <em>ger</em> (resident alien) who was protected and cared for by the Israelite social laws (14:29; 16:11; 24:17-21) now becomes Israel's superior. The social order described in the laws (Israelite hosts, foreign residents as guests requiring hospitality) is completely reversed. This is both a historical observation (in exile, Israelites became the low-status foreigners in someone else's land) and a theological judgment.</p>",
        "44": "<p>\"He will lend to you, but you will not lend to him. He will be the head, and you will be the tail\" — the precise inversion of vv12-13: the blessing promised Israel would lend to nations and be the head; the curse delivers the opposite. The resident alien, protected in Israelite law, now becomes the creditor-landlord over Israel. The head/tail hierarchy of v13 is reversed. Nehemiah's memoir documents exactly this dynamic in the Persian-period restoration (Neh 5:1-5).</p>",
        "45": "<p>\"All these curses will come upon you. They will pursue and overtake you until you are destroyed, because you did not obey the LORD your God and observe the commands and decrees he gave you\" — the summary-conclusion of the first curse series: all the curses pursue and overtake — the same verb (<em>nasag</em>) as the blessings in v2 but with destructive outcome. The curses are as relentless as the blessings would have been. The cause is stated plainly: non-obedience (<em>asher lo shamata</em>) to YHWH's commands and decrees.</p>",
        "46": "<p>\"They will be a sign and a wonder against you and your descendants forever\" — the curse as a sign (<em>ot</em>) and wonder (<em>mofet</em>): the same language used for the Exodus miracles (Exod 4:21; 7:3; Deut 4:34; 6:22; 7:19; 26:8; 34:11) is applied to the curses. The plagues of Egypt were signs and wonders of redemption; the covenant-curses are signs and wonders of judgment. Both display the same divine sovereignty over human history, but in opposite directions of the covenant relationship. The \"forever\" indicates that the historical witness-function of the curses is permanent and international.</p>",
        "47": "<p>\"Because you did not serve the LORD your God joyfully and gladly in the time of prosperity\" — the hinge verse of chapter 28: the curses are traced not to outright apostasy but to the failure of joyful service. Israel served YHWH, but without joy (<em>simchah vetuv levav</em>, joyfulness and goodness of heart). The covenant was kept technically but not wholeheartedly. This verse is the Deuteronomic answer to the question \"why did the exile happen even when the external forms of worship were maintained?\" Malachi 1:13 captures the same failure: \"What a burden!\" said of worship.</p>",
        "48": "<p>\"You will serve the enemies the LORD sends against you in hunger, thirst, nakedness, and dire poverty. He will put an iron yoke on your neck until he has destroyed you\" — the service-contrast: instead of serving YHWH joyfully in prosperity (v47), Israel serves enemies in the four deprivations of conquered existence. The \"iron yoke\" (<em>ol barzel</em>) on the neck is the specific image of Assyrian conquest: Assyrian royal inscriptions describe vanquished kings as dogs on a leash or cattle under a yoke. Jeremiah employs this exact imagery for Babylon's domination of Judah (Jer 28:14).</p>",
        "49": "<p>\"The LORD will bring against you a nation from far away, from the ends of the earth, that swoops down like an eagle\" — the eagle-nation: the distant empire that comes as an eagle (<em>nesher</em>, H5404 — eagle or vulture, the great aerial predator) swooping from the ends of the earth. The eagle imagery is used for Assyria (Isa 10:14) and Babylon (Ezek 17:3 uses the eagle for Nebuchadnezzar; Hab 1:8 for the Babylonians). The phrase \"ends of the earth\" (<em>miqtseh ha'aretz</em>) emphasizes the imperial reach: no geographic distance protects the covenant-breaker. The specificity of the eagle-swooping-from-afar is remarkable in a text composed before either empire had conquered Israel.</p>",
        "50": "<p>\"A fierce-looking nation without respect for the old or pity for the young\" — the characterization of the conquering nation: harsh in appearance (<em>az panim</em>), without the ANE's core social-honor values. In the honor-shame culture of the ancient Near East, even war had certain protocols: respecting elders and protecting children were minimum markers of civilized conduct. The invading nation violates both — a signal of total dehumanization in the conquest. The historical Assyrian and Babylonian armies were documented in their own inscriptions as agents of total terror, including the deportation of entire populations regardless of age.</p>",
        "51": "<p>\"They will devour the young of your livestock and the crops of your land until you are destroyed. They will leave you no grain, new wine, or olive oil, nor any calves of your herds or lambs of your flocks until they have ruined you\" — the three staples of Israelite agricultural economy (grain, wine, oil — the triad of covenant blessing, Deut 7:13; 11:14) are stripped to zero by the conquering army. The comprehensive economic devastation echoes the agricultural curses of vv38-40 but now by human military agency rather than natural plague.</p>",
        "52": "<p>\"They will lay siege to all your cities throughout your land until the high, fortified walls in which you trusted fall down\" — the siege-warfare curse: the fortified city was the ultimate defensive resource of an ancient state. Israel's trust in city walls rather than YHWH's protection is a recurring prophetic critique (Isa 22:11; Jer 5:17; Hab 2:9-11). The siege reduces even the strongest fortifications to rubble. Archaeological evidence of deliberate destruction of city-walls is abundant in 8th-6th c. BCE Levantine sites: Lachish (documented in 2 Kgs 18-19 and in the Lachish reliefs at Nineveh), Jerusalem (586 BCE Babylonian destruction).</p>",
        "53": "<p>\"In the desperation of the siege your enemies impose on you, you will eat the flesh of your own children — your sons and daughters the LORD your God has given you\" — the siege-cannibalism curse: the most extreme form of starvation-desperation in ancient siege warfare. This was not a theoretical curse: 2 Kings 6:28-29 records it happening during Ben-Hadad's siege of Samaria (ca. 850 BCE); Josephus (<em>Jewish War</em> 6.3.4) records it during Titus's siege of Jerusalem (70 CE); Lamentations 2:20 and 4:10 document it for the Babylonian siege of 586 BCE. The curse became history at least three times. The identification of the children as YHWH's gift (<em>asher natan lecha YHWH eloheicha</em>) intensifies the horror: the blessing of v4 (fruit of the womb) is consumed by its recipients.</p>",
        "54": "<p>\"Even the most sensitive and refined man among you will become stingy with his brother, the wife he loves, and his surviving children\" — the siege creates a reversal of the open-hand generosity commanded throughout Deuteronomy. The man who would normally embody covenant-generosity (open hand toward the poor, 15:8,11) becomes the most extreme hoarder when covenant-curses bring famine through siege. The specific relationships named (brother, beloved wife, surviving children) are the innermost circle of covenant social bonds — the siege-famine destroys even these core relationships through competition over survival-food.</p>",
        "55": "<p>\"Refusing to share with any of them the flesh of his own children that he is eating — because nothing is left\" — the impossibility of normative behavior under siege conditions: the phrase \"because nothing is left\" (<em>mibeli hisheir lo kol</em>) is both factual and the theological reversal of the covenant's abundance promises. The total absence of surplus — which the covenant promised as blessing (v12) — is the material condition in which all human-social goods collapse. The covenant's social ethic requires economic margin; the curses eliminate all margin.</p>",
        "56": "<p>\"The most delicate and sensitive woman among you — so refined she would never place her foot on the ground — will begrudge the husband she loves and her own son and daughter\" — the socially elevated woman represents the highest social class in Israel (the description suggests aristocratic refinement — she has never had to walk on rough ground). If even she reaches this point, the entire society has reached it. The social stratification of vv54-57 moves from the sensitive man (v54) to the delicate woman (v56), indicating that no level of social privilege provides protection from the siege-famine's dehumanizing effects.</p>",
        "57": "<p>\"Even the afterbirth from her womb and the children she bears — she will secretly eat them, so dire will be her need during the siege of your city\" — the afterbirth (<em>shilya</em>, H7988) is mentioned in the Torah only here: in extremis, the most hidden, intimate biological material of childbirth becomes a food source. The secrecy (<em>baseser</em>) indicates shame — the act is so horrifying that even in the social collapse of siege, it must be hidden. Josephus's account of the siege of Jerusalem (<em>Jewish War</em> 6.3.3-4) narrates a specific incident of a woman named Mary who ate her infant during the 70 CE siege.</p>",
        "58": "<p>\"If you do not carefully follow all the words of this law, which are written in this book, and do not revere this glorious and awesome Name — the LORD your God\" — the second major condition-statement in the curse section: it introduces the final and most extreme curses (vv59-68). The phrase \"this law, which is written in this book\" (<em>divrei hatorah hazot haketuvim basefer hazeh</em>) is a self-referential moment: Deuteronomy explicitly describes itself as a written text (<em>sefer</em>) with legal authority — a remarkable textual self-consciousness. The \"glorious and awesome Name\" frames what is at stake: not merely legal compliance but honor of YHWH's character.</p>",
        "59": "<p>\"The LORD will send you and your descendants extraordinary disasters — severe and prolonged plagues, terrible and lingering illnesses\" — the escalation in the final curse series: the plagues are now described with doubled intensive adjectives (<em>peliot veneemanut</em>, extraordinary and confirmed; <em>ra'ot veneemanut</em>, terrible and confirmed). The confirmation/persistence (<em>neemanu</em>, from <em>aman</em>, to be firm, enduring) is significant — these are not passing afflictions but enduring, established divine judgments. The word-play with the covenant's Amen-structure is implicit: the covenant's confirmed promises work both ways.</p>",
        "60": "<p>\"He will bring on you all the diseases of Egypt that you dreaded, and they will cling to you\" — the Egypt-disease return (cf. v27): the diseases that YHWH promised to keep away from the obedient (Deut 7:15) are now brought back and made to cling (<em>davaq</em>, the same verb used for covenant-loyalty in 4:4; 10:20; 11:22). The clinging that was covenant-faithfulness's posture toward YHWH is now the curses' posture toward the covenant-breaker. The irony: the covenant-breaker who would not cling to YHWH is clung to by Egypt's plagues.</p>",
        "61": "<p>\"The LORD will also bring on you every kind of sickness and disaster not recorded in this Book of the Law, until you are destroyed\" — the open-ended curse: not only the specific curses listed but every sickness and disaster not yet named. This is a rhetorical acknowledgment that the list cannot be complete: divine judgment exceeds any list. The self-referential \"this Book of the Law\" (<em>sefer hatorah hazeh</em>) signals Deuteronomy's awareness of itself as canonical written text.</p>",
        "62": "<p>\"You who were as numerous as the stars in the sky will be left but few in number, because you did not obey the LORD your God\" — the stars-of-the-sky comparison reverses the Abrahamic promise: Gen 15:5 (\"your offspring will be as numerous as the stars\") and Deut 1:10 are directly inverted. The covenant promise of numerical multiplication, which was the fulfillment of the patriarchal blessing, becomes the measure of its loss. The historical fulfillment: the Babylonian exile of 586 BCE reduced the population of Judah from an estimated 200,000+ to a remnant of a few thousand, with the majority deported or fled to Egypt.</p>",
        "63": "<p>\"Just as the LORD delighted in making you prosper and multiply, so he will delight in bringing you to ruin and destruction\" — the most theologically startling verse in Deuteronomy: YHWH's delight (<em>yasis YHWH</em>) in Israel's prosperity is matched by an equal delight in Israel's ruin. The same divine pleasure that energized the covenant's blessings now energizes its curses. This is not arbitrary divine sadism but the covenant's binary structure applied to the divine character: YHWH takes his covenant seriously enough to enforce both poles with equal energy. The ANE's patron-deity model assumed the deity always favored his nation; Deuteronomy's covenant theology breaks this assumption completely.</p>",
        "64": "<p>\"The LORD will scatter you among all nations, from one end of the earth to the other. There you will serve gods of wood and stone, which neither you nor your ancestors have known\" — the diaspora-curse: dispersal to all nations is the final form of covenant judgment. The contrast with the Exodus-gathering: YHWH gathered Israel from Egypt to one land; the curse scatters Israel from one land to all nations. The wood-and-stone idol service in exile is both punishment and irony: Israel's desire for other gods (implied in v14's breach) is now imposed on them in exile without the option of YHWH's central sanctuary.</p>",
        "65": "<p>\"Among those nations you will find no repose, no resting place for the sole of your foot. There the LORD will give you an anxious mind, eyes worn out with longing, and a despairing soul\" — the exile's existential character: no <em>noacha</em> (rest) or <em>margoa</em> (resting-place). The three inner experiences of exile: <em>lev ragaz</em> (anxious/trembling heart), <em>kilyon einayim</em> (eyes worn out with longing), and <em>deabon nefesh</em> (soul-languishing). The longing-eyes mirror the exiled parent's eyes straining toward the horizon for children who never return (v32). The diaspora is not merely political dispossession but chronic psychological displacement.</p>",
        "66": "<p>\"Your life will hang in the balance — you will live in constant dread, day and night, never sure of your survival\" — the existential insecurity of exile: no day or night brings rest from the fear of death. The phrase \"your life will hang in the balance\" (<em>vehayu chayeicha teluyim lecha mineged</em>) may be an image of the life hanging by a thread before one's eyes. This is the experiential core of the curse: not only material deprivation but the psychological horror of perpetual insecurity. Psalm 22 and Lamentations 3 give voice to exactly this experience.</p>",
        "67": "<p>\"In the morning you will say, 'If only it were evening!' and in the evening you will say, 'If only it were morning!' — because of the dread in your heart and the sights your eyes will see\" — the temporal-inversion curse: the normal human rhythm (dreading the night, looking forward to morning) is reversed. Evening cannot bring the comfort of rest; morning cannot bring the comfort of new possibility. The exile-community cannot find relief in time's natural rhythms. This is the opposite of Psalm 30:5 (\"Weeping endures for the night; joy comes in the morning\") — in the curse-condition, neither morning nor evening brings the expected change.</p>",
        "68": "<p>\"The LORD will send you back to Egypt in ships, along a route I said you would never travel again. There you will offer yourselves for sale to your enemies as male and female slaves, but no one will buy you\" — the ultimate curse-climax: return to Egypt by ship. The Exodus had delivered Israel from Egyptian slavery; the curse closes the covenant's narrative arc by reversing the Exodus completely. The ships may indicate a Mediterranean sea-route to Egypt. The final indignity: offering oneself as a slave but finding no buyers — even slavery is denied. Josephus (<em>Jewish War</em> 6.9.2-3) notes that after the 70 CE fall of Jerusalem, Jewish captives were sold into Egyptian slavery, with many finding no buyers due to the surplus of war-captives.</p>"
    },
    "29": {
        "1": "<p>\"These are the terms of the covenant the LORD commanded Moses to make with the Israelites in Moab, in addition to the covenant he had made with them at Horeb\" — the Moab covenant is explicitly presented as a second, additional covenant, not a replacement of Sinai/Horeb. The Hebrew syntax (<em>levad mehabrit asher karat itam bechorev</em>) is emphatic: \"besides/in addition to the covenant.\" This raises a covenantal-theological question that the rabbis debated: is the Moab covenant a renewal of Sinai, an extension, or a distinct covenant? The book of Deuteronomy frames the Moab covenant as the third covenant in sequence: the Abrahamic (Gen 15; 17), the Sinaitic (Exod 19-24), and the Moab covenant — which extends to all future generations (vv14-15). The NT's new covenant (Jer 31:31-34) is yet another covenant in this progressive sequence.</p>",
        "2": "<p>\"Moses summoned all Israel and said to them: 'You have seen with your own eyes everything the LORD did in Egypt to Pharaoh, to all his officials, and to all his land'\" — the covenant-rehearsal opening: Moses begins the covenant-renewal ceremony with the same rhetorical move as the Decalogue's preamble (5:6: \"I am the LORD your God, who brought you out of Egypt\"). The covenant is grounded in historical acts — what YHWH did, which Israel saw (<em>raitem et kol asher asa</em>). The first-person plural inclusivity of the address extends the Sinai generation's experience to the Moab generation standing before Moses.</p>",
        "3": "<p>\"Those great trials, the signs and wonders you saw with your own eyes\" — the trial-signs-wonders triad for the Exodus miracles (cf. Deut 4:34; 7:19; 26:8): <em>massot gedolot</em> (great trials), <em>ha'otot</em> (the signs), <em>hamoftim</em> (the wonders). The triple description emphasizes both the scale and the evidential nature of the Exodus events. They were designed to be seen (<em>asher ra'u eineicha</em>) — their purpose included the testimony they provided to Israel and the nations about YHWH's character and power. Paul cites the Exodus events as a warning to the church (1 Cor 10:1-11: \"these things happened to them as examples\").</p>",
        "4": "<p>\"Yet to this day the LORD has not given you a mind that understands or eyes that see or ears that hear\" — the incomprehension indictment: despite the miraculous witness of the Exodus, Israel does not comprehend. The inability to understand is attributed to YHWH's not-yet-giving (<em>velo natan YHWH lachem</em>): understanding, seeing eyes, and hearing ears are divine gifts, not natural human faculties. This is not fatalistic determinism but a covenant-theological statement about the depth of human spiritual dullness — even spectacular miracles do not automatically produce understanding. Paul quotes v4 in Romans 11:8 in his discussion of Israel's hardening: \"God gave them a spirit of stupor, eyes that would not see and ears that would not hear, down to this very day.\"</p>",
        "5": "<p>\"For forty years I led you through the wilderness. Your clothes did not wear out, and your sandals did not wear out on your feet\" — the wilderness provision as a sign of YHWH's care that should have produced understanding (v4): the miraculous preservation of clothing and sandals for forty years is a quiet miracle compared to the plagues and Red Sea crossing. The ordinariness of the sign is its point — YHWH's care extends to the mundane (clothing, footwear) as well as the spectacular. Nehemiah 9:21 repeats this as part of the covenant-history recitation: a mark of sustained providential care throughout the wilderness generation.</p>",
        "6": "<p>\"You ate no bread and drank no wine or other fermented drink — so that you would know that I am the LORD your God\" — the wilderness diet of manna and water (rather than bread and wine) is a sustained revelatory sign: YHWH sustained Israel with unusual food to demonstrate his identity as provider beyond normal agricultural means. The purpose clause (<em>lema'an teda'u</em>) states the intended pedagogical function of the wilderness experience. The bread-and-wine contrast with manna-and-water will reappear in the NT: Jesus's \"bread of life\" discourse (John 6) explicitly contrasts himself with the manna, as does the Eucharist's bread-and-wine over against the ordinary food the wilderness generation received.</p>",
        "7": "<p>\"When you reached this place, Sihon king of Heshbon and Og king of Bashan came out to fight against us, and we defeated them\" — the Transjordanian victories (Num 21:21-35; Deut 2:24-3:11) are cited as the most recent evidence of YHWH's faithfulness before the Jordan crossing. Sihon and Og became the paradigmatic examples of YHWH's military power on Israel's behalf (Ps 135:11; 136:19-20; Neh 9:22). Their defeat was the first conquest-territory and demonstrated that the same power that operated in the Exodus was still operative at the boundary of the promised land.</p>",
        "8": "<p>\"We took their land and gave it as an inheritance to the Reubenites, the Gadites, and the half-tribe of Manasseh\" — the Transjordanian tribal allotments (Num 32; Deut 3:12-20) are mentioned as established facts: the east-Jordan tribes already have their inheritance, demonstrating that YHWH's distribution of the land has begun before the Jordan crossing. The east-Jordan settlement serves as a down-payment and guarantee of the west-Jordan settlement to come. The inclusion of these tribes in the covenant ceremony (vv10-11) ensures that the Transjordanian territory is within the covenant's scope.</p>",
        "9": "<p>\"Observe the terms of this covenant and carry them out, so that you may be successful in everything you do\" — the covenant-obedience imperative: <em>shemartem et divrei habrit hazot</em> (keep the words of this covenant). The verb <em>shamar</em> (keep, guard, observe, H8104) is Deuteronomy's central obedience verb — appearing over 40 times in the book. Joshua 1:7-8 quotes this verse almost exactly in YHWH's commissioning of Joshua: the new leader must keep the Torah book and meditate on it day and night in order to be successful.</p>",
        "10": "<p>\"All of you are standing today in the presence of the LORD your God — your leaders and chief men, your elders and officials, and all the other men of Israel\" — the covenant community catalogue begins: the social hierarchy is enumerated top-to-bottom (<em>rasheichem shivteichem zeqeneichem veshotereichem</em>). The covenant assembly is explicitly structured to include every social stratum. The leaders and officials who might administer the covenant's laws, the elders who provide community wisdom, and the general male population are all named — they all stand before YHWH as covenant-parties, not spectators.</p>",
        "11": "<p>\"Together with your children and wives, and the foreigners living in your camp who chop your wood and carry your water\" — the covenant community's horizontal extension: women and children (who had no legal standing in most ANE covenant and treaty contexts) and the resident foreign laborers at the bottom of the social hierarchy are all explicitly included. The wood-choppers and water-carriers were the lowest-status workers in the camp — possibly Gibeonites (Josh 9:21-27 describes the Gibeonites as hewers of wood and drawers of water, apparently in fulfillment of this covenant's terms). Their inclusion is a covenant-theological statement: YHWH's covenant reaches even to the margins of the community.</p>",
        "12": "<p>\"You are here to enter into a covenant with the LORD your God, a covenant the LORD is making with you today and sealing with an oath\" — the covenant as an oath-sealed (<em>shevu'ah</em>) agreement: the combination of covenant (<em>brit</em>) and oath (<em>alah</em>) is the suzerainty treaty's binding formula. By swearing an oath, the vassal calls down the curse-consequences upon himself if he violates the stipulations (the curse-list of ch 28 is precisely these oath-consequences). YHWH's faithfulness to his covenant promises is assumed; Israel's oath-sworn obligation is what is being renewed here.</p>",
        "13": "<p>\"To confirm you this day as his people, that he may be your God as he promised you and as he swore to your ancestors Abraham, Isaac, and Jacob\" — the covenant renewal fulfills the patriarchal promises: the three-patriarch formula connects the Moab covenant to Gen 17:7 (\"I will be your God and the God of your descendants after you\"). The covenant formula — \"he may be your God\" and \"you his people\" — is the covenant's relational essence in its most compressed form. It appears throughout the OT (Exod 6:7; Lev 26:12; Jer 7:23; 31:33; 32:38; Ezek 36:28; Rev 21:3) as the covenant's permanent goal.</p>",
        "14": "<p>\"I am making this covenant, with its oath, not only with you who stand here today before the LORD our God\" — the temporal extension of the covenant: the Moab covenant is explicitly made not only with those physically present (the generation standing at Moab) but also with those not yet there. This is the covenant's intergenerational extension — the contractual relationship binds descendants who did not personally participate in the ceremony. The same principle is asserted for the Sinai covenant (5:2-3: \"not with our ancestors... but with us, all of us who are alive here today\") and is fundamental to covenant theology's understanding of corporate identity across time.</p>",
        "15": "<p>\"But also with those who are not here with us today\" — the future-generation extension: those not yet born are included in the covenant. Peter's Pentecost sermon quotes this principle (Acts 2:39: \"the promise is for you and your children and for all who are far off\"). The NT's understanding of the new covenant as available to \"all nations\" (Matt 28:19) and to \"Jew and Greek\" (Rom 1:16) is the universal extension of this intergenerational-extension principle. The covenant's temporal reach across generations is matched in the new covenant by a spatial reach across nations.</p>",
        "16": "<p>\"You remember how we lived in Egypt and how we traveled through the nations on your way here\" — the anti-idolatry argument from experience: Israel has been through Egypt and through the Transjordanian nations, and has seen their religious practices firsthand. The memory of pagan nations' worship systems is not to stimulate nostalgia but to inoculate against temptation. The reminder that Israel saw these things with their own eyes continues the witness-language of the chapter: covenant faithfulness is grounded in what Israel has actually seen of both YHWH's acts (vv2-3) and pagan alternatives (vv16-18).</p>",
        "17": "<p>\"You saw their detestable images — their idols of wood, stone, silver, and gold\" — the idol-materials catalogue: wood and stone (the natural, low-cost materials) alongside silver and gold (the high-value cult-images). The four-material list encompasses the full range of idol-manufacture. Deuteronomy's consistent characterization of idols as human-made objects of wood, stone, and metal (4:28; 28:36,64; 29:17) strips them of divine pretense: they are craft-objects, not deities. Isaiah 40-44 develops this critique most fully: the same tree provides material for a fire and for a god (Isa 44:16-17) — an absurdity.</p>",
        "18": "<p>\"Make sure there is no man or woman, clan or tribe among you today whose heart turns away from the LORD our God to go and worship the gods of those nations; make sure there is no root among you that produces such bitter poison\" — the \"root of bitterness\" (<em>shoresh poreh rosh veleanah</em>) — a root that bears gall and bitterness. The phrase is quoted in Hebrews 12:15: \"See to it that no one fails to obtain the grace of God; that no 'root of bitterness' springs up and causes trouble, and by it many become defiled.\" The root-metaphor is apt: apostasy begins underground, hidden in the heart, before it surfaces in visible worship.</p>",
        "19": "<p>\"One who hears the terms of this oath and yet reassures himself, thinking, 'I will be safe, even though I persist in going my own way'\" — the self-reassuring covenant-member: the internal rationalization that covenant membership provides safety regardless of personal faithfulness. The phrase \"I will be safe\" (<em>shalom yihyeh li</em>, lit. \"peace will be to me\") is the false prophet's message in Jer 6:14 and 8:11: \"Peace, peace\" when there is no peace. The person in v19 applies the false-prophet's logic to himself — claiming covenant-blessing language (<em>shalom</em>) for his own disobedient condition. The NT parallel: those who claim covenant identity without covenant transformation (Rom 2:17-24; Jas 2:14-17).</p>",
        "20": "<p>\"The LORD will never pardon him. Instead, the LORD's anger and his jealousy will burn against that person; all the curses written in this book will fall on him, and the LORD will blot out his name from under heaven\" — the unpardonable self-rationalizing apostate: the one who has heard the covenant and deliberately chosen to transgress while claiming covenant safety will not be pardoned. The phrase \"blot out his name\" (<em>macha et shemo</em>) is the formal removal from the Book of Life — the covenant-register (cf. Exod 32:32-33; Ps 69:28; Rev 3:5). The divine jealousy (<em>qin'ato</em>, H7068) is the exclusive-covenant claim YHWH makes on his people — the same jealousy that grounds the second commandment's prohibition of idolatry (5:9).</p>",
        "21": "<p>\"The LORD will single him out from all the tribes of Israel for disaster, in keeping with all the curses of the covenant written in this Book of the Law\" — the individual singled out from the collective: the apostasy of an individual within the covenant community is not covered by the community's covenant. The singling-out (<em>hivdil YHWH oto lera'ah</em>) for evil from among the tribes is the negative application of Israel's being set apart (<em>hivdil</em>) from the nations for holiness (Lev 20:24,26). The same divine act that separated Israel as holy from the nations now separates the apostate as condemned from Israel.</p>",
        "22": "<p>\"Your descendants who follow you and foreigners who come from distant lands will see the calamities that fall on that land and the diseases the LORD has inflicted on it\" — the international witness to judgment: the nations observe Israel's punishment and recognize its divine cause. The future-generations perspective sets the curse's impact in a broader temporal frame: the land's devastation will be visible and interpretable for centuries. This picks up the theme from 28:37 (Israel becomes a horror and byword among the nations) but now frames the nations' observation as leading to a theological explanation (vv24-25).</p>",
        "23": "<p>\"They will see the whole land laid waste with burning sulfur and salt — nothing planted, nothing sprouting, no vegetation growing on it. It will be like the destruction of Sodom and Gomorrah, Admah, and Zeboiim, which the LORD overthrew in fierce anger\" — the Sodom-comparison is the ultimate ancient benchmark for divine judgment and total destruction. The four cities of the plain (Gen 14:2) were destroyed by fire and sulfur (Gen 19:24). Salt and sulfur soil is permanently sterile. The comparison is applied in Isaiah 1:9, 13:19; Jer 49:18; 50:40; Amos 4:11; Zeph 2:9. The Sodom-standard became a set phrase for the most complete imaginable divine destruction.</p>",
        "24": "<p>\"All the nations will ask: 'Why has the LORD done this to this land? Why this fierce, burning anger?'\" — the nations' question frames vv22-28 as an international theodicy: observers of Israel's devastation will ask the theological question \"why?\" The question implies that the nations recognize YHWH as the agent of the destruction — not Babylon or Assyria as the ultimate cause but YHWH acting through them. The same question-and-answer structure appears in 1 Kings 9:8-9, Jer 22:8-9, and 2 Chr 7:21-22.</p>",
        "25": "<p>\"And the answer will be: 'It is because this people abandoned the covenant of the LORD, the God of their ancestors, the covenant he made with them when he brought them out of Egypt'\" — the official theological interpretation of the exile: covenant-abandonment. The answer is given not by Israelites but by the nations — even foreigners can read the theological meaning of Israel's historical catastrophe from the documentary evidence of the covenant-curse structure. The Deuteronomistic History (Judges through 2 Kings) presents itself as the fulfillment of exactly this prophesied explanation: the fall of Israel (722 BCE) and Judah (586 BCE) are both interpreted as covenant-abandonment (2 Kgs 17:7-23; 24:2-4).</p>",
        "26": "<p>\"They went and worshiped other gods and bowed down to them — gods they had not known, gods he had not given them\" — the precise breach: worshiping gods YHWH had not authorized (<em>asher lo yadaum</em>, which they had not known; <em>asher lo chalaq lahem</em>, which he had not allotted to them). The \"allotted to them\" phrase may refer to Deut 4:19's statement that YHWH allotted the celestial bodies to other nations — Israel's allotment was YHWH himself, not the stellar deities. To worship the allotted-for-others gods was to transgress the covenant's territorial principle with catastrophic consequences.</p>",
        "27": "<p>\"Therefore the LORD's anger burned against this land, so that he brought on it all the curses written in this book\" — the direct causation stated: the curses of ch 28 are not arbitrary historical misfortune but covenant-documented, prophesied consequences of covenant-breach. The phrase \"all the curses written in this book\" makes the theological argument: what the nations observe (vv22-23) and what the nations explain (vv24-26) is the fulfillment of documented covenant-stipulations. History is covenant-theology made visible in time.</p>",
        "28": "<p>\"In furious anger and great wrath the LORD uprooted them from their land and thrust them into another land, as it is now\" — the exile as a completed act: the text anticipates the final state. The phrase \"as it is now\" (<em>kayom hazeh</em>) is either a late editorial note reflecting the Babylonian exile's completion, or a prophetic present-tense anticipation of the exile's certainty. Jeremiah 24:6 uses the same uprooting/transplanting metaphor (\"I will plant them and not uproot them\") for the restoration — the exile's uprooting is not permanent but is itself a covenant action that has a restoration-counterpart (30:1-10).</p>",
        "29": "<p>\"The secret things belong to the LORD our God, but the things revealed belong to us and to our children forever, so that we may follow all the words of this law\" — the hermeneutical capstone of the Moab covenant: two categories of divine reality are distinguished. The hidden things (<em>hanistarot</em>) — YHWH's undisclosed purposes, his eternal decrees, the timing of future events — belong to YHWH alone. The revealed things (<em>haniglot</em>) — the Torah, the covenant stipulations, the blessing-and-curse structure — belong to Israel permanently. The verse sets the boundaries of both human knowledge and human responsibility: not everything is knowable, but everything necessary for obedience is known. This is one of the most important epistemological principles in the OT: covenant responsibility is bounded by covenant revelation. Paul's doxology in Romans 11:33-36 (\"Oh, the depth of the riches and wisdom and knowledge of God! How unsearchable his judgments and how inscrutable his ways!\") is the NT equivalent — some things are beyond human comprehension; what is revealed is sufficient for faith and practice.</p>"
    }
}


def main():
    existing = load_comm("mkt-context", "deuteronomy")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, DEUT)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-context", "deuteronomy", existing)
    print(f"Deuteronomy mkt-context: {after} verse entries total (+{after - before} new)")
    for ch in ["28", "29"]:
        total = {"28": 68, "29": 29}[ch]
        present = len(existing.get(ch, {}))
        missing = [str(i) for i in range(1, total + 1) if str(i) not in existing.get(ch, {})]
        print(f"  Ch {ch}: {present}/{total} — missing: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
